      "context": "Possible upstream regulator; indirect evidence within the paper"
    }
  ],
  "pathways": [
    {
      "pathway_name": "Excitatory synapse signaling / PSD-95–dependent synaptic maintenance",
      "role": "scaffold/adaptor",
      "evidence": "Overexpression of TANC1 increases spine and excitatory synapse density; PDZ-binding motif required; knockout mice show reduced spine density and hippocampal-dependent spatial memory deficits",
      "pmid": "39737163"
    }
  ],
  "functions": [
    {
      "function": "Postsynaptic scaffold/adaptor protein organizing multi-protein signaling complexes at excitatory synapses",
      "evidence": "Direct PSD-95 binding via PDZ motif; assembly with GKAP, AMPA/NMDA receptors, and CaMKII; PDZ motif depletion abrogates spine/synapse density effects",
      "pmid": "39737163"
    },
    {
      "function": "Subcellular localization and tissue expression",
      "evidence": "Localizes to excitatory synapses; hippocampal enrichment with prominent CA3 and CA1/dentate gyrus expression; hippocampus-dominant pattern relative to TANC2",
      "pmid": "39737163"
    },
    {
      "function": "Regulation of dendritic spines and excitatory synapses",
      "evidence": "Overexpression increases spine density and excitatory synapse density; C-terminal PDZ-binding motif required; TANC1 deficiency reduces spine/synapse maintenance and impairs spatial memory",
      "pmid": "39737163"
    },
    {
      "function": "Phenotype associated with TANC1 deficiency",
      "evidence": "Tanc1 knockout mice (h11002/h11002) show decreased spatial memory in Morris water maze; normal locomotion and anxiety-like behaviors",
      "pmid": "39737163"
    }
  ],
  "summary": "TANC1 is a postsynaptic density–associated scaffold that directly binds PSD-95 through its C-terminal PDZ-binding motif and anchors a multi-protein complex including GKAP, AMPA receptors, NMDA receptors, and CaMKII at excitatory synapses. It localizes predominantly to hippocampal excitatory synapses, particularly in CA3 neurons, and its PDZ-motif–dependent function promotes dendritic spine and synapse density. In vivo, TANC1 deficiency impairs hippocampal-dependent spatial memory, while overexpression increases spine/synapse density, supporting a critical role for TANC1 in synaptic signaling and structural plasticity in the hippocampus."
}

